parameters.jsCode:
const strategy = $input.first().json.output || {};
const lead = $('Test Data - Stage 3 Ready').item.json;

// Parse pain points if string
let painPoints = [];
try {
  painPoints = typeof lead.pain_points === 'string' 
    ? JSON.parse(lead.pain_points) 
    : lead.pain_points || [];
} catch (e) {
  painPoints = [];
}

// COMPREHENSIVE FINAL SCORE (0-100)
let finalScore = 0;

// 1. Contact Data Quality (20 points)
if (lead.email) finalScore += 15;
if (lead.domain) finalScore += 5;

// 2. Business Intelligence (25 points)
if (lead.company_size === 'medium' || lead.company_size === 'large') {
  finalScore += 15;
} else if (lead.company_size === 'small') {
  finalScore += 10;
}
if (painPoints.length >= 3) finalScore += 10;

// 3. Business Health (20 points)
if (lead.rating >= 4.5) finalScore += 12;
else if (lead.rating >= 4.0) finalScore += 8;
else if (lead.rating >= 3.5) finalScore += 4;

if (lead.review_count > 500) finalScore += 8;
else if (lead.review_count > 100) finalScore += 5;
else if (lead.review_count > 20) finalScore += 3;

// 4. Personalization Quality (20 points)
if (lead.personalization_hook && lead.personalization_hook.length > 20) {
  finalScore += 10;
}
if (strategy.email_subject_line && strategy.email_subject_line.length > 0) {
  finalScore += 10;
}

// 5. Outreach Readiness (15 points)
const responseRate = parseInt(strategy.estimated_response_rate) || 0;
if (responseRate >= 25) finalScore += 15;
else if (responseRate >= 15) finalScore += 10;
else if (responseRate >= 10) finalScore += 5;

// ==============================
// SMS & WHATSAPP SCORING (NEW)
// ==============================

// SMS/WhatsApp channel bonus
if (strategy.sms_strategy?.should_use) {
  finalScore += 5;
}

if (strategy.whatsapp_strategy?.should_use) {
  finalScore += 5;
}

// Multi-channel availability bonus
const channelCount = [
  strategy.email_strategy?.should_use,
  strategy.linkedin_strategy?.should_use,
  strategy.sms_strategy?.should_use,
  strategy.whatsapp_strategy?.should_use
].filter(Boolean).length;

if (channelCount >= 3) {
  finalScore += 10;
}

// ==============================

// Determine Priority
let priority = 'cold';
if (finalScore >= 75) priority = 'hot';
else if (finalScore >= 55) priority = 'warm';

// Engagement Readiness
let engagement = 'not_ready';
if (lead.email && finalScore >= 70) {
  engagement = 'ready';
} else if (finalScore >= 50) {
  engagement = 'needs_nurturing';
}

// Optimal contact hour based on timezone
let optimalHour = 10; // Default 10 AM
if (lead.detected_timezone && lead.detected_timezone.includes('America')) {
  optimalHour = 10;
}

return {
  lead_id: lead.id,
  company_name: lead.company_name,

  // Outreach Strategy
  email_subject_line: strategy.email_subject_line || null,
  opening_hook: strategy.opening_sentence || null,
  pain_point_focus: strategy.pain_point_to_address || null,
  value_proposition: strategy.value_proposition || null,
  social_proof_needed: strategy.social_proof_angle || null,
  call_to_action: strategy.call_to_action || null,
  timing_recommendation: strategy.best_send_time || null,
  follow_up_sequence: JSON.stringify({
    day_3: strategy.follow_up_day_3 || null,
    day_7: strategy.follow_up_day_7 || null
  }),
  recommended_tone: strategy.recommended_tone || 'professional',
  conversation_starters: JSON.stringify(strategy.conversation_starters || []),

  // NEW: Channel Strategies
  sms_strategy: JSON.stringify(strategy.sms_strategy || {}),
  whatsapp_strategy: JSON.stringify(strategy.whatsapp_strategy || {}),

  // Scoring
  lead_score: Math.min(100, finalScore),
  priority: priority,
  engagement_readiness: engagement,
  optimal_contact_hour: optimalHour,
  estimated_response_rate: strategy.estimated_response_rate || 'unknown',

  // Metadata
  enrichment_stage: 3,
  enrichment_complete: true
};
